static common_chat_params common_chat_params_init_mistral_instruct_v3(
    const common_chat_template &          tmpl,
    const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Mistral Instruct v0.3 prepends the system message to the *first* user
    // turn rather than keeping it as a separate message.
    auto        adjusted_messages = json::array();
    std::string system_content;
    bool        has_system = false;

    for (const auto & msg : inputs.messages) {
        if (!has_system && msg.value("role", "") == "system") {
            has_system = true;
            if (msg.contains("content") && msg.at("content").is_string()) {
                system_content = msg.at("content").get<std::string>();
            }
            continue;  // drop standalone system message; will be inlined below
        }
        adjusted_messages.push_back(msg);
    }

    if (has_system && !system_content.empty()) {
        for (auto & msg : adjusted_messages) {
            if (msg.value("role", "") == "user" && msg.contains("content") &&
                msg.at("content").is_string()) {
                msg["content"] =
                    system_content + "\n\n" + msg.at("content").get<std::string>();
                break;
            }
        }
    }

    data.prompt = common_chat_template_direct_apply_impl(
        tmpl, inputs, /* messages_override = */ adjusted_messages);
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        return p.prefix(inputs.generation_prompt) << p.content(p.rest());
    });
    data.parser = parser.save();
    return data;
}

